using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Breaking change: Sync I/O now throws by default in EF Core 9 Cosmos.
        // Either switch all calls to async (preferred) or opt in to sync I/O:
        optionsBuilder.ConfigureWarnings(w =>
            w.Ignore(Microsoft.EntityFrameworkCore.Diagnostics.CosmosEventId.SyncNotSupported));
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: HasIndex now throws for Cosmos (was silently ignored).
        // Remove the HasIndex call — Cosmos indexing is managed server-side.

        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change: Discriminator property renamed from "Discriminator" to "$type".
            // Preserve old property name for backward compat with existing documents.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change: id format changed from "EntityType|Key" to just "Key".
            // Preserve old format for backward compat with existing documents.
            b.HasPartitionKey(e => e.Id);
            b.Property(e => e.Id).ToJsonProperty("id");
            b.UseETagConcurrency();
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

